// ─────────────────────────────────────────────────────────────────────────────
// 西嶽華山真形圖 · 親筆
// 據圖版：參攷-local/五嶽真形圖/Gujin_Tushu_Jicheng_pic010_五嶽真形圖.png（華嶽）
// 判準：古今圖書集成（1726）明碑一系摹刻；錨自 24 指格網逐點讀出（格_hua.png）。
// 幅比 0.66（高≈15.8 指）。式：一體連塊如鳥——左雙喙、頂焰四舌、右角長伸；
// 體中含目（白環抱黑珠，珠含雙環竅），目右白月牙二道。鑿筆（蔽法）開白。
// 二輪（2026-07-12）：左喙増肉、底左尾垂長、目環偏東南加寬、月牙貼環放大、
// 珠竅改環（鑿環＋塊心）。
// ─────────────────────────────────────────────────────────────────────────────
import { 卵 } from '../fubi.js';
export const 華嶽真形 = (bi) => {
    // 主體一塊（順時針自上喙尖起）
    bi.塊(t => t.M(-11.7, 8.0)
        .C(-9.7, 7.2, -8.2, 6.8, -7.0, 6.5) // 上喙上緣入體
        .C(-6.8, 6.0, -6.6, 5.6, -6.4, 5.2) // 焰一（小）
        .C(-6.1, 5.9, -5.9, 6.3, -5.6, 6.7) // 谷一
        .C(-5.3, 5.4, -5.0, 3.9, -4.6, 2.7) // 焰二（高）
        .C(-4.2, 4.3, -3.7, 5.4, -2.9, 6.0) // 谷二
        .C(-1.7, 4.8, -0.4, 3.1, 0.5, 2.1) // 焰三
        .C(0.9, 3.5, 1.4, 4.7, 2.3, 5.4) // 谷三
        .C(3.3, 3.9, 4.7, 2.1, 5.8, 0.8) // 焰四（大）
        .C(6.1, 2.0, 6.3, 2.9, 6.7, 3.6) // 谷四
        .C(8.5, 2.5, 10.3, 2.2, 11.9, 2.3) // 右角尖（微揚）
        .C(10.5, 4.3, 8.8, 5.5, 7.5, 6.2) // 角下緣回鋒
        .C(8.4, 8.0, 8.8, 10.0, 8.4, 11.6) // 體右緣外弸
        .C(7.8, 13.6, 5.6, 14.8, 3.0, 15.3) // 右下轉底
        .C(0.4, 15.8, -2.6, 15.7, -5.2, 15.1) // 底緣西行
        .C(-7.8, 14.4, -9.6, 14.7, -11.5, 15.4) // 底左尾尖（增肉）
        .C(-10.2, 14.15, -8.9, 13.4, -7.9, 12.75) // 尾上凹（淺）
        .C(-9.6, 12.85, -11.1, 12.5, -11.9, 12.0) // 下喙尖（楔厚）
        .C(-10.5, 11.2, -9.7, 10.7, -8.9, 10.15) // 喙間凹（淺）
        .C(-9.8, 9.4, -10.7, 8.7, -11.7, 8.0) // 回上喙尖（楔厚）
        .close());
    // 目：白環（鑿，偏東南）抱黑珠（塊），珠含雙環竅（鑿環＋塊心）
    bi.鑿(t => 卵(t, -1.9, 10.2, 3.5, 2.9, 0.12));
    bi.塊(t => 卵(t, -2.5, 10.0, 2.0, 1.9));
    bi.鑿(t => 卵(t, -3.0, 9.5, 0.5, 0.48));
    bi.塊(t => 卵(t, -3.0, 9.5, 0.2, 0.19));
    bi.鑿(t => 卵(t, -1.95, 10.5, 0.5, 0.48));
    bi.塊(t => 卵(t, -1.95, 10.5, 0.2, 0.19));
    // 目右白月牙二道（鑿——貼環而行，體豐）
    bi.鑿(t => t.M(0.4, 6.8)
        .C(2.3, 7.6, 2.9, 9.5, 1.6, 11.4)
        .C(1.9, 9.6, 1.35, 8.0, 0.4, 6.8)
        .close());
    bi.鑿(t => t.M(2.6, 7.2)
        .C(3.9, 8.0, 4.1, 9.3, 3.2, 10.6)
        .C(3.55, 9.3, 3.3, 8.2, 2.6, 7.2)
        .close());
};
